from fastapi import APIRouter, Depends, HTTPException
from sqlalchemy.orm import Session

from app.api.deps import get_db
from app.schemas.project import FileCreate, FileOut, ProjectCreate, ProjectDetail, ProjectOut, ProjectUpdate
from app.services import project_service

router = APIRouter(prefix="/projects")


@router.get("", response_model=list[ProjectOut])
def list_projects(db: Session = Depends(get_db)):
    return project_service.get_projects(db)


@router.post("", response_model=ProjectOut, status_code=201)
def create_project(data: ProjectCreate, db: Session = Depends(get_db)):
    return project_service.create_project(db, data)


@router.get("/{project_id}", response_model=ProjectDetail)
def get_project(project_id: int, db: Session = Depends(get_db)):
    project = project_service.get_project(db, project_id)
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    files = project_service.get_project_files(db, project_id)
    return {
        "id": project.id,
        "name": project.name,
        "description": project.description,
        "created_at": project.created_at,
        "updated_at": project.updated_at,
        "file_count": len(files),
        "files": files,
    }


@router.put("/{project_id}", response_model=ProjectOut)
def update_project(project_id: int, data: ProjectUpdate, db: Session = Depends(get_db)):
    project = project_service.update_project(db, project_id, data)
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    files = project_service.get_project_files(db, project_id)
    return {
        "id": project.id,
        "name": project.name,
        "description": project.description,
        "created_at": project.created_at,
        "updated_at": project.updated_at,
        "file_count": len(files),
    }


@router.delete("/{project_id}", status_code=204)
def delete_project(project_id: int, db: Session = Depends(get_db)):
    ok = project_service.delete_project(db, project_id)
    if not ok:
        raise HTTPException(status_code=404, detail="Project not found")


@router.get("/{project_id}/files", response_model=list[FileOut])
def list_files(project_id: int, db: Session = Depends(get_db)):
    project = project_service.get_project(db, project_id)
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    return project_service.get_project_files(db, project_id)


@router.post("/{project_id}/files", response_model=FileOut, status_code=201)
def add_file(project_id: int, data: FileCreate, db: Session = Depends(get_db)):
    project = project_service.get_project(db, project_id)
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    return project_service.add_file(db, project_id, data)


@router.delete("/{project_id}/files/{file_id}", status_code=204)
def delete_file(project_id: int, file_id: int, db: Session = Depends(get_db)):
    ok = project_service.delete_file(db, file_id)
    if not ok:
        raise HTTPException(status_code=404, detail="File not found")

