/* ============================================
   VAULT — Dark industrial file manager
   Fonts: Syne (display) + DM Mono (mono)
   Theme: Ink black, stark white, orange accent
   ============================================ */

*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  --font-display: 'Syne', sans-serif;
  --font-mono:    'DM Mono', monospace;

  --ink:         #0a0a0a;
  --ink-2:       #141414;
  --ink-3:       #1e1e1e;
  --ink-4:       #2a2a2a;
  --line:        #2e2e2e;
  --white:       #f5f5f0;
  --white-dim:   #9a9a90;
  --orange:      #ff5c1a;
  --orange-dim:  #c44313;
  --green:       #3ddc84;
  --red:         #ff4444;

  --sidebar-w: 260px;
  --transition: 200ms ease;
}

html, body {
  height: 100%;
  font-family: var(--font-mono);
  background: var(--ink);
  color: var(--white);
  -webkit-font-smoothing: antialiased;
  overflow: hidden;
}

/* ========== UTILITY ========== */
.hidden { display: none !important; }

/* ========== LAYOUT ========== */
body {
  display: grid;
  grid-template-columns: var(--sidebar-w) 1fr;
  height: 100vh;
}

/* ========== SIDEBAR ========== */
.sidebar {
  background: var(--ink-2);
  border-right: 1px solid var(--line);
  display: flex;
  flex-direction: column;
  height: 100vh;
  overflow: hidden;
  position: relative;
}

.sidebar__brand {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 28px 20px 24px;
  border-bottom: 1px solid var(--line);
  flex-shrink: 0;
}

.brand__icon {
  font-size: 20px;
  color: var(--orange);
  line-height: 1;
}

.brand__name {
  font-family: var(--font-display);
  font-weight: 800;
  font-size: 18px;
  letter-spacing: 0.12em;
  color: var(--white);
}

.btn--new-project {
  display: flex;
  align-items: center;
  gap: 8px;
  margin: 16px 16px 8px;
  padding: 10px 14px;
  background: var(--orange);
  color: var(--ink);
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 13px;
  letter-spacing: 0.04em;
  border: none;
  cursor: pointer;
  transition: background var(--transition);
  flex-shrink: 0;
}

.btn--new-project:hover {
  background: #ff7a44;
}

.btn__plus {
  font-size: 18px;
  line-height: 1;
  font-weight: 400;
}

.sidebar__section-label {
  padding: 16px 20px 8px;
  font-size: 10px;
  letter-spacing: 0.15em;
  color: var(--white-dim);
  font-family: var(--font-display);
  font-weight: 600;
  flex-shrink: 0;
}

.project-list {
  flex: 1;
  overflow-y: auto;
  padding: 4px 0 16px;
}

.project-list::-webkit-scrollbar { width: 3px; }
.project-list::-webkit-scrollbar-track { background: transparent; }
.project-list::-webkit-scrollbar-thumb { background: var(--ink-4); }

.project-item {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 20px;
  cursor: pointer;
  transition: background var(--transition);
  border-left: 2px solid transparent;
