  padding: 14px 28px;
  background: transparent;
  border: 1px solid var(--line);
  color: var(--white);
  font-family: var(--font-display);
  font-weight: 600;
  font-size: 14px;
  letter-spacing: 0.06em;
  cursor: pointer;
  transition: all var(--transition);
}

.btn--ghost-lg:hover {
  border-color: var(--orange);
  color: var(--orange);
}

/* ========== PROJECT VIEW ========== */
.project-view {
  height: 100vh;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.project-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  padding: 28px 36px 24px;
  border-bottom: 1px solid var(--line);
  flex-shrink: 0;
  gap: 16px;
}

.project-header__label {
  display: block;
  font-size: 10px;
  letter-spacing: 0.15em;
  color: var(--orange);
  font-family: var(--font-display);
  font-weight: 600;
  margin-bottom: 6px;
}

.project-header__name {
  font-family: var(--font-display);
  font-weight: 800;
  font-size: clamp(22px, 3vw, 36px);
  line-height: 1.1;
  letter-spacing: -0.01em;
  color: var(--white);
}

.project-header__desc {
  font-size: 13px;
  color: var(--white-dim);
  margin-top: 6px;
  line-height: 1.5;
}

.project-header__actions {
  display: flex;
  gap: 8px;
  flex-shrink: 0;
  padding-top: 4px;
}

.btn--icon {
  width: 34px;
  height: 34px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--ink-3);
  border: 1px solid var(--line);
  color: var(--white-dim);
  font-size: 15px;
  cursor: pointer;
  transition: all var(--transition);
}

.btn--icon:hover {
  border-color: var(--white-dim);
  color: var(--white);
}

.btn--icon.btn--danger:hover {
  border-color: var(--red);
  color: var(--red);
  background: rgba(255,68,68,0.08);
}

/* ========== UPLOAD ZONE ========== */
.upload-zone {
  padding: 24px 36px;
  flex-shrink: 0;
  border-bottom: 1px solid var(--line);
}

.upload-zone__inner {
  border: 1px dashed var(--line);
  padding: 28px;
  text-align: center;
  cursor: pointer;
  transition: all var(--transition);
  position: relative;
}

.upload-zone__inner:hover,
.upload-zone__inner.drag-over {
  border-color: var(--orange);
  background: rgba(255, 92, 26, 0.04);
}

.upload-zone__icon {
  font-size: 32px;
  color: var(--ink-4);
  margin-bottom: 8px;
  font-weight: 300;
  transition: color var(--transition);
}

.upload-zone__inner:hover .upload-zone__icon {
  color: var(--orange);
}

.upload-zone__text {
  font-size: 13px;
  color: var(--white-dim);
}

.upload-zone__link {
  color: var(--orange);
  cursor: pointer;
  text-decoration: underline;
  text-underline-offset: 3px;
}

.upload-zone__hint {
  font-size: 11px;
  color: var(--ink-4);
  margin-top: 6px;
  letter-spacing: 0.04em;
}

.upload-progress {
  margin-top: 12px;
}

.upload-progress__bar {
  height: 3px;
  background: var(--ink-4);
  overflow: hidden;
}

.upload-progress__fill {
  height: 100%;
  background: var(--orange);
  width: 0%;
  transition: width 300ms ease;
}

.upload-progress__text {
  display: block;
  font-size: 11px;
  color: var(--white-dim);
  margin-top: 6px;
  font-family: var(--font-mono);
}

/* ========== FILES SECTION ========== */
.files-section {
  flex: 1;
  overflow-y: auto;
  padding: 20px 36px 36px;
}

.files-section::-webkit-scrollbar { width: 4px; }
.files-section::-webkit-scrollbar-track { background: transparent; }
.files-section::-webkit-scrollbar-thumb { background: var(--ink-4); }

.files-section__header {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 16px;
}

.files-section__label {
  font-size: 10px;
  letter-spacing: 0.15em;
  color: var(--white-dim);
  font-family: var(--font-display);
  font-weight: 600;
}

.files-section__count {
  font-size: 10px;
  font-family: var(--font-mono);
  color: var(--orange);
  background: rgba(255, 92, 26, 0.12);
  padding: 2px 6px;
  border-radius: 2px;
}

.file-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
  gap: 12px;
}

.file-card {
  background: var(--ink-2);
  border: 1px solid var(--line);
  cursor: pointer;
  transition: all var(--transition);
  position: relative;
  overflow: hidden;
  animation: fadeUp 300ms ease both;
}

.file-card:hover {
  border-color: var(--orange);
  transform: translateY(-2px);
}

@keyframes fadeUp {
  from { opacity: 0; transform: translateY(8px); }
  to   { opacity: 1; transform: translateY(0); }
}

.file-card__preview {
  width: 100%;
  aspect-ratio: 4/3;
  object-fit: cover;
  display: block;
  background: var(--ink-3);
}

.file-card__thumb {
  width: 100%;
  aspect-ratio: 4/3;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  background: var(--ink-3);
  gap: 8px;
}

.file-card__type-icon {
  font-size: 28px;
  color: var(--white-dim);
}

.file-card__ext {
  font-size: 9px;
  letter-spacing: 0.1em;
  color: var(--white-dim);
  font-family: var(--font-display);
  font-weight: 700;
  background: var(--ink-4);
  padding: 2px 5px;
}

.file-card__body {
  padding: 10px 12px 8px;
}

.file-card__name {
  font-size: 11px;
  font-family: var(--font-mono);
  color: var(--white);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  line-height: 1.4;
}

.file-card__size {
  font-size: 10px;
  color: var(--white-dim);
  margin-top: 2px;
}

.file-card__delete {
  position: absolute;
  top: 6px;
  right: 6px;
  width: 24px;
  height: 24px;
  background: rgba(10,10,10,0.85);
  border: 1px solid var(--line);
  color: var(--white-dim);
  font-size: 11px;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  transition: all var(--transition);
}

.file-card:hover .file-card__delete {
  opacity: 1;
}

.file-card__delete:hover {
  background: var(--red);
  border-color: var(--red);
  color: #fff;
}

.state-empty {
  grid-column: 1 / -1;
  text-align: center;
  padding: 48px 20px;
  color: var(--white-dim);
}

.state-empty__icon {
  font-size: 40px;
  margin-bottom: 12px;
  color: var(--ink-4);
}

.state-empty p {
  font-size: 13px;
}

/* ========== MODAL ========== */
.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.75);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 100;
  animation: fadeIn 150ms ease;
  padding: 20px;
}

@keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }

.modal {
  background: var(--ink-2);
  border: 1px solid var(--line);
  width: 100%;
  max-width: 460px;
  animation: slideUp 200ms ease;
}

@keyframes slideUp {
  from { opacity: 0; transform: translateY(20px); }
  to   { opacity: 1; transform: translateY(0); }
}

.modal--preview {
  max-width: 800px;
  background: var(--ink);
  padding: 0;
  position: relative;
}

.modal__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 20px 24px 16px;
  border-bottom: 1px solid var(--line);
}

.modal__title {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 18px;
  letter-spacing: -0.01em;
  color: var(--white);
}

.modal__close {
  width: 28px;
  height: 28px;
  background: transparent;
  border: 1px solid var(--line);
  color: var(--white-dim);
  font-size: 12px;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all var(--transition);
}

.modal__close:hover {
  border-color: var(--red);
  color: var(--red);
}

.modal__close--preview {
  position: absolute;
  top: 12px;
  right: 12px;
  z-index: 10;
  background: rgba(10,10,10,0.85);
}

.modal__form {
  padding: 24px;
}

.form-group {
  margin-bottom: 18px;
}

.form-label {
  display: block;
  font-size: 11px;
  letter-spacing: 0.1em;
  color: var(--white-dim);
  font-family: var(--font-display);
  font-weight: 600;
  margin-bottom: 8px;
}

.form-input {
  width: 100%;
  background: var(--ink-3);
  border: 1px solid var(--line);
  color: var(--white);
  font-family: var(--font-mono);
  font-size: 13px;
  padding: 10px 12px;
  outline: none;
  transition: border-color var(--transition);
  resize: none;
}

.form-input::placeholder { color: var(--ink-4); }

.form-input:focus {
  border-color: var(--orange);
}

.form-textarea {
  resize: vertical;
  min-height: 80px;
}

.form-error {
  display: block;
  font-size: 11px;
  color: var(--red);
  margin-top: 5px;
}

.form-actions {
  display: flex;
  gap: 10px;
  justify-content: flex-end;
  margin-top: 24px;
}

.btn--ghost {
  padding: 9px 18px;
  background: transparent;
  border: 1px solid var(--line);
  color: var(--white-dim);
  font-family: var(--font-display);
  font-weight: 600;
  font-size: 12px;
  letter-spacing: 0.06em;
  cursor: pointer;
  transition: all var(--transition);
}

.btn--ghost:hover {
  border-color: var(--white-dim);
  color: var(--white);
}

.btn--primary {
  padding: 9px 22px;
  background: var(--orange);
  border: 1px solid var(--orange);
  color: var(--ink);
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 12px;
  letter-spacing: 0.06em;
  cursor: pointer;
  transition: background var(--transition);
}

.btn--primary:hover {
  background: #ff7a44;
  border-color: #ff7a44;
}

/* ========== PREVIEW ========== */
.preview-content {
  padding: 40px 40px 0;
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 300px;
  max-height: 70vh;
  overflow: hidden;
}

.preview-content img {
  max-width: 100%;
  max-height: 65vh;
  object-fit: contain;
  display: block;
}

.preview-content video,
.preview-content audio {
  max-width: 100%;
}

.preview-content iframe {
  width: 100%;
  height: 65vh;
  border: none;
}

.preview-meta {
  padding: 16px 40px 28px;
  font-size: 12px;
  color: var(--white-dim);
  border-top: 1px solid var(--line);
  margin-top: 16px;
}

/* ========== UPLOAD STATE OVERLAY ========== */
.uploading-overlay {
  position: absolute;
  inset: 0;
  background: rgba(10,10,10,0.6);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 14px;
  z-index: 20;
}

.uploading-overlay .spinner {
  width: 28px;
  height: 28px;
  border-width: 3px;
}

.uploading-overlay span {
  font-size: 13px;
  color: var(--white-dim);
}

/* ========== RESPONSIVE ========== */
@media (max-width: 700px) {
  body {
    grid-template-columns: 1fr;
    grid-template-rows: auto 1fr;
    overflow: auto;
  }

  .sidebar {
    height: auto;
    max-height: 50vh;
  }

  .main {
    height: auto;
    overflow: visible;
  }

  .project-view {
    height: auto;
    overflow: visible;
  }

  .files-section {
    overflow: visible;
  }

  .file-grid {
    grid-template-columns: repeat(auto-fill, minmax(130px, 1fr));
  }

  .upload-zone,
  .project-header,
  .files-section {
    padding-left: 16px;
    padding-right: 16px;
  }
}
