/**
 * Vault — Project & File Manager
 * Main application logic
 */

// ============================================================
// STATE
// ============================================================
let currentProjectId = null;
let projects = [];

// ============================================================
// DOM REFS
// ============================================================
const $ = id => document.getElementById(id);

const dom = {
  projectList:     $('project-list'),
  projectsLoading: $('projects-loading'),
  projectsEmpty:   $('projects-empty'),
  welcomeView:     $('welcome-view'),
  projectView:     $('project-view'),
  projectName:     $('project-name'),
  projectDesc:     $('project-desc'),
  fileGrid:        $('file-grid'),
  filesLoading:    $('files-loading'),
  filesEmpty:      $('files-empty'),
  fileCount:       $('file-count'),
  fileInput:       $('file-input'),
  dropArea:        $('drop-area'),
  uploadProgress:  $('upload-progress'),
  uploadFill:      $('upload-fill'),
  uploadText:      $('upload-text'),
  modalOverlay:    $('modal-overlay'),
  modalTitle:      $('modal-title'),
  modalSubmit:     $('btn-modal-submit'),
  projectForm:     $('project-form'),
  inputName:       $('input-name'),
  inputDesc:       $('input-desc'),
  errorName:       $('error-name'),
  previewOverlay:  $('preview-overlay'),
  previewContent:  $('preview-content'),
  previewMeta:     $('preview-meta'),
};

// ============================================================
// UTILS
// ============================================================
function escapeHtml(text) {
  const div = document.createElement('div');
  div.textContent = String(text ?? '');
  return div.innerHTML;
}

function formatBytes(bytes) {
  if (!bytes || bytes === 0) return '—';
  if (bytes < 1024) return bytes + ' B';
  if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
  return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
}

function formatDate(iso) {
  return new Date(iso).toLocaleDateString('vi-VN', {
    day: '2-digit', month: '2-digit', year: 'numeric'
  });
}

function getFileCategory(filename, mimeType = '') {
  const ext = filename.split('.').pop().toLowerCase();
  const mime = mimeType.toLowerCase();

  if (mime.startsWith('image/') || ['jpg','jpeg','png','gif','webp','svg','bmp','ico','tiff'].includes(ext))
    return 'image';
  if (mime.startsWith('video/') || ['mp4','webm','mov','avi','mkv','flv'].includes(ext))
    return 'video';
