function buildFileCard(file) {
  const category = getFileCategory(file.filename, file.file_type || '');
  const ext = file.filename.split('.').pop().toUpperCase();
  const card = document.createElement('div');
  card.className = 'file-card';
  card.dataset.fileId = file.id;

  let thumbHtml;
  if (category === 'image') {
    thumbHtml = `<img class="file-card__preview" src="${escapeHtml(file.file_url)}" alt="${escapeHtml(file.filename)}" loading="lazy" onerror="this.parentElement.innerHTML='<div class=\\'file-card__thumb\\'><div class=\\'file-card__type-icon\\'>${getFileIcon(category)}</div><span class=\\'file-card__ext\\'>${escapeHtml(ext)}</span></div>'" />`;
  } else {
    thumbHtml = `
      <div class="file-card__thumb">
        <div class="file-card__type-icon">${getFileIcon(category)}</div>
        <span class="file-card__ext">${escapeHtml(ext)}</span>
