async function deleteFile(fileId, cardEl) {
  try {
    await apiDelete(`/api/projects/${currentProjectId}/files/${fileId}`);
    cardEl.style.transition = 'opacity 200ms';
    cardEl.style.opacity = '0';
    setTimeout(() => {
      cardEl.remove();
      const remaining = dom.fileGrid.querySelectorAll('.file-card').length;
      dom.fileCount.textContent = remaining;
      if (remaining === 0) {
        dom.filesEmpty.classList.remove('hidden');
        dom.fileGrid.appendChild(dom.filesEmpty);
      }
      updateProjectCount(currentProjectId, remaining);
    }, 200);
