  dom.errorName.classList.add('hidden');
  dom.inputName.style.borderColor = '';
  dom.modalOverlay.classList.remove('hidden');
  setTimeout(() => dom.inputName.focus(), 50);
}

function openEditModal(project) {
  editingProjectId = project.id;
  dom.modalTitle.textContent = 'Edit Project';
  dom.modalSubmit.textContent = 'Save';
  dom.inputName.value = project.name;
  dom.inputDesc.value = project.description || '';
  dom.errorName.classList.add('hidden');
  dom.inputName.style.borderColor = '';
  dom.modalOverlay.classList.remove('hidden');
  setTimeout(() => dom.inputName.focus(), 50);
}

function closeModal() {
  dom.modalOverlay.classList.add('hidden');
}

$('btn-new-project').addEventListener('click', openCreateModal);
$('btn-welcome-new').addEventListener('click', openCreateModal);
$('modal-close').addEventListener('click', closeModal);
$('btn-modal-cancel').addEventListener('click', closeModal);

dom.modalOverlay.addEventListener('click', (e) => {
  if (e.target === dom.modalOverlay) closeModal();
});

dom.projectForm.addEventListener('submit', async (e) => {
  e.preventDefault();
  const name = dom.inputName.value.trim();

  if (!name) {
    dom.inputName.style.borderColor = 'var(--red)';
    dom.errorName.textContent = 'Project name is required.';
    dom.errorName.classList.remove('hidden');
    dom.inputName.focus();
    return;
  }

  dom.errorName.classList.add('hidden');
  dom.inputName.style.borderColor = '';
  dom.modalSubmit.disabled = true;
  dom.modalSubmit.textContent = editingProjectId ? 'Saving...' : 'Creating...';

  const payload = { name, description: dom.inputDesc.value.trim() || null };

  try {
    if (editingProjectId) {
      await api.put(`/api/projects/${editingProjectId}`, payload);
    } else {
      const created = await api.post('/api/projects', payload);
      closeModal();
      await loadProjects();
      openProject(created.id);
      return;
    }
    closeModal();
    await loadProjects();
    // Refresh current view
    if (currentProjectId) {
      const p = projects.find(p => p.id === currentProjectId);
      if (p) {
        dom.projectName.textContent = p.name;
        dom.projectDesc.textContent = p.description || '';
      }
    }
  } catch (err) {
    alert('Error: ' + err.message);
  } finally {
    dom.modalSubmit.disabled = false;
    dom.modalSubmit.textContent = editingProjectId ? 'Save' : 'Create';
  }
});

// ============================================================
// EDIT / DELETE CURRENT PROJECT
// ============================================================
$('btn-edit-project').addEventListener('click', () => {
  if (!currentProjectId) return;
  const p = projects.find(p => p.id === currentProjectId);
  if (p) openEditModal(p);
});

$('btn-delete-project').addEventListener('click', async () => {
  if (!currentProjectId) return;
  const p = projects.find(p => p.id === currentProjectId);
  if (!p) return;

  if (!confirm(`Delete project "${p.name}" and all its files? This cannot be undone.`)) return;

  try {
    await apiDelete(`/api/projects/${currentProjectId}`);
    currentProjectId = null;
    dom.projectView.classList.add('hidden');
    dom.welcomeView.classList.remove('hidden');
    await loadProjects();
  } catch (err) {
    alert('Failed to delete project: ' + err.message);
  }
});

// ============================================================
// INIT
// ============================================================
document.addEventListener('DOMContentLoaded', () => {
  loadProjects();
});

