  const item = dom.projectList.querySelector(`[data-id="${projectId}"]`);
  if (item) {
    const countEl = item.querySelector('.project-item__count');
    if (countEl) countEl.textContent = `${count} file${count !== 1 ? 's' : ''}`;
  }
}

// ============================================================
// UPLOAD
// ============================================================
dom.fileInput.addEventListener('change', () => {
  if (dom.fileInput.files.length > 0) {
    uploadFiles(Array.from(dom.fileInput.files));
    dom.fileInput.value = '';
  }
});

// Drag & Drop
dom.dropArea.addEventListener('dragover', (e) => {
  e.preventDefault();
  dom.dropArea.classList.add('drag-over');
});

dom.dropArea.addEventListener('dragleave', () => {
  dom.dropArea.classList.remove('drag-over');
});

dom.dropArea.addEventListener('drop', (e) => {
  e.preventDefault();
  dom.dropArea.classList.remove('drag-over');
  if (!currentProjectId) return;
  const files = Array.from(e.dataTransfer.files);
  if (files.length > 0) uploadFiles(files);
});

async function uploadFiles(files) {
  if (!currentProjectId) return;

  dom.uploadProgress.classList.remove('hidden');
  dom.dropArea.style.pointerEvents = 'none';

  let uploaded = 0;
  for (const file of files) {
    try {
      dom.uploadText.textContent = `Uploading ${escapeHtml(file.name)}... (${uploaded + 1}/${files.length})`;
      dom.uploadFill.style.width = `${(uploaded / files.length) * 100}%`;

      // 1. Get presigned URL
      const { upload_url, file_url } = await api.post('/api/upload/presigned-url', {
        filename: file.name
      });

      // 2. PUT to S3
      await fetch(upload_url, {
        method: 'PUT',
        body: file,
        headers: { 'Content-Type': file.type || 'application/octet-stream' },
      });

      // 3. Save metadata
      await api.post(`/api/projects/${currentProjectId}/files`, {
        filename: file.name,
        file_url: file_url,
        file_type: file.type || null,
        file_size: file.size,
      });

      uploaded++;
      dom.uploadFill.style.width = `${(uploaded / files.length) * 100}%`;
    } catch (err) {
      console.error(`Failed to upload ${file.name}:`, err);
      alert(`Failed to upload "${file.name}": ${err.message}`);
    }
  }

  dom.uploadText.textContent = `Done — ${uploaded} file${uploaded !== 1 ? 's' : ''} uploaded.`;
  setTimeout(() => {
    dom.uploadProgress.classList.add('hidden');
    dom.uploadFill.style.width = '0%';
  }, 2000);

  dom.dropArea.style.pointerEvents = '';

  // Refresh file list
  if (currentProjectId) {
    const project = await api.get(`/api/projects/${currentProjectId}`);
    renderFiles(project.files);
    updateProjectCount(currentProjectId, project.files.length);
  }
}

// ============================================================
// PREVIEW MODAL
// ============================================================
function openPreview(file) {
  const category = getFileCategory(file.filename, file.file_type || '');
  let contentHtml = '';

  if (category === 'image') {
    contentHtml = `<img src="${escapeHtml(file.file_url)}" alt="${escapeHtml(file.filename)}" />`;
  } else if (category === 'video') {
    contentHtml = `<video controls><source src="${escapeHtml(file.file_url)}" type="${escapeHtml(file.file_type || '')}">Your browser does not support video.</video>`;
  } else if (category === 'audio') {
    contentHtml = `<audio controls style="width:100%"><source src="${escapeHtml(file.file_url)}" type="${escapeHtml(file.file_type || '')}">Your browser does not support audio.</audio>`;
  } else if (category === 'pdf') {
    contentHtml = `<iframe src="${escapeHtml(file.file_url)}" title="${escapeHtml(file.filename)}"></iframe>`;
  } else {
    contentHtml = `
      <div style="text-align:center;padding:40px 20px">
        <div style="font-size:60px;margin-bottom:16px">${getFileIcon(category)}</div>
        <p style="color:var(--white-dim);margin-bottom:20px">Preview not available for this file type.</p>
        <a href="${escapeHtml(file.file_url)}" target="_blank" rel="noopener noreferrer"
           style="color:var(--orange);font-family:var(--font-display);font-weight:700;letter-spacing:0.06em;text-decoration:none;">
          OPEN FILE &rarr;
        </a>
      </div>`;
  }

  dom.previewContent.innerHTML = contentHtml;
  dom.previewMeta.innerHTML = `
    <strong style="color:var(--white)">${escapeHtml(file.filename)}</strong>
    &nbsp;&middot;&nbsp; ${formatBytes(file.file_size)}
    &nbsp;&middot;&nbsp; ${formatDate(file.created_at)}
  `;
  dom.previewOverlay.classList.remove('hidden');
}

$('preview-close').addEventListener('click', closePreview);
dom.previewOverlay.addEventListener('click', (e) => {
  if (e.target === dom.previewOverlay) closePreview();
});

function closePreview() {
  dom.previewOverlay.classList.add('hidden');
  dom.previewContent.innerHTML = '';
  dom.previewMeta.innerHTML = '';
}

// ============================================================
// PROJECT MODAL (Create / Edit)
// ============================================================
let editingProjectId = null;

function openCreateModal() {
  editingProjectId = null;
  dom.modalTitle.textContent = 'New Project';
  dom.modalSubmit.textContent = 'Create';
  dom.projectForm.reset();
  dom.errorName.classList.add('hidden');
  dom.inputName.style.borderColor = '';
  dom.modalOverlay.classList.remove('hidden');
  setTimeout(() => dom.inputName.focus(), 50);
}

function openEditModal(project) {
  editingProjectId = project.id;
  dom.modalTitle.textContent = 'Edit Project';
  dom.modalSubmit.textContent = 'Save';
  dom.inputName.value = project.name;
  dom.inputDesc.value = project.description || '';
  dom.errorName.classList.add('hidden');
  dom.inputName.style.borderColor = '';
  dom.modalOverlay.classList.remove('hidden');
  setTimeout(() => dom.inputName.focus(), 50);
}

function closeModal() {
  dom.modalOverlay.classList.add('hidden');
}

$('btn-new-project').addEventListener('click', openCreateModal);
$('btn-welcome-new').addEventListener('click', openCreateModal);
$('modal-close').addEventListener('click', closeModal);
$('btn-modal-cancel').addEventListener('click', closeModal);

dom.modalOverlay.addEventListener('click', (e) => {
  if (e.target === dom.modalOverlay) closeModal();
});

dom.projectForm.addEventListener('submit', async (e) => {
  e.preventDefault();
  const name = dom.inputName.value.trim();

  if (!name) {
    dom.inputName.style.borderColor = 'var(--red)';
    dom.errorName.textContent = 'Project name is required.';
    dom.errorName.classList.remove('hidden');
    dom.inputName.focus();
    return;
  }

  dom.errorName.classList.add('hidden');
  dom.inputName.style.borderColor = '';
  dom.modalSubmit.disabled = true;
  dom.modalSubmit.textContent = editingProjectId ? 'Saving...' : 'Creating...';

  const payload = { name, description: dom.inputDesc.value.trim() || null };

  try {
    if (editingProjectId) {
      await api.put(`/api/projects/${editingProjectId}`, payload);
    } else {
      const created = await api.post('/api/projects', payload);
      closeModal();
      await loadProjects();
      openProject(created.id);
      return;
    }
    closeModal();
    await loadProjects();
    // Refresh current view
    if (currentProjectId) {
      const p = projects.find(p => p.id === currentProjectId);
      if (p) {
        dom.projectName.textContent = p.name;
        dom.projectDesc.textContent = p.description || '';
      }
    }
  } catch (err) {
    alert('Error: ' + err.message);
  } finally {
    dom.modalSubmit.disabled = false;
    dom.modalSubmit.textContent = editingProjectId ? 'Save' : 'Create';
  }
});

// ============================================================
// EDIT / DELETE CURRENT PROJECT
// ============================================================
$('btn-edit-project').addEventListener('click', () => {
  if (!currentProjectId) return;
  const p = projects.find(p => p.id === currentProjectId);
  if (p) openEditModal(p);
});

$('btn-delete-project').addEventListener('click', async () => {
  if (!currentProjectId) return;
  const p = projects.find(p => p.id === currentProjectId);
  if (!p) return;

  if (!confirm(`Delete project "${p.name}" and all its files? This cannot be undone.`)) return;

  try {
    await apiDelete(`/api/projects/${currentProjectId}`);
    currentProjectId = null;
    dom.projectView.classList.add('hidden');
    dom.welcomeView.classList.remove('hidden');
    await loadProjects();
  } catch (err) {
    alert('Failed to delete project: ' + err.message);
  }
});

// ============================================================
// INIT
// ============================================================
document.addEventListener('DOMContentLoaded', () => {
  loadProjects();
});
